import { Typography, TypographyProps } from '@mui/material';
import { fontWeights } from '@/constants/ThemeConstants';

// Use theme palette tokens (text.primary / secondary / disabled) so these
// helpers automatically follow light/dark/high-contrast mode.
export const PageTitle = (props: TypographyProps) => (
  <Typography variant="h5" sx={{ fontWeight: fontWeights.medium, color: 'text.primary', mb: 2 }} {...props} />
);

export const SectionHeading = (props: TypographyProps) => (
  <Typography variant="h6" sx={{ fontWeight: fontWeights.medium, color: 'text.primary', mb: 1.5 }} {...props} />
);

export const BodyText = (props: TypographyProps) => (
  <Typography variant="body1" sx={{ color: 'text.primary' }} {...props} />
);

export const Caption = (props: TypographyProps) => (
  <Typography variant="caption" sx={{ color: 'text.secondary' }} {...props} />
);

export const MetaLabel = (props: TypographyProps) => (
  <Typography variant="body2" sx={{ color: 'text.disabled', fontSize: '0.75rem' }} {...props} />
);
